var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야! 클론에 대한 단서를 확보했다!","JPN":"ユイちゃん！　クローンに関する手掛かりが見つかったわ！","ENG":"Jia! I found the clue about the clone!","TWN":"小佳！我找到有關複製人的資料了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지금 바로 베타트릭스 1호점으로 올 수 있겠느냐?! 한 시가 급한 일이니라!","JPN":"今すぐベータトリックス1号店に来てくれる？　大至急よ！","ENG":"Could you come to Betatrix No. 1 right now?! It’s urgent!","TWN":"你現在可以趕快來貝塔崔克斯1號店一趟嗎？刻不容緩！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아, 리더! 왜 이렇게 늦었어?","JPN":"あっ、リーダー！　遅いじゃない！","ENG":"Leader! What took you so long?","TWN":"老大！你怎麼這麼慢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여러분? 어떻게 여기에……?","JPN":"皆さん？　なぜここに……？","ENG":"Huh? How did you all...?","TWN":"大家？你們怎麼會在這裡……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"왜 그래? 범인에 대한 단서를 찾았으니까 얼른 와 달라고 했잖아?","JPN":"どうしたの？　犯人に関する手掛かりを見つけたから早く来てほしいって\\n言ってたでしょ？","ENG":"Hmm? Didn’t you tell us to come here because you found a clue about the suspect?","TWN":"你怎麼會問我們？不是你說找到有關犯人的線索，叫我們趕快過來的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私がですか？","ENG":"Huh? Me?","TWN":"什麼？我叫你們來？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"낌새가 이상하네요. 들어가지 않는 편이 좋겠어요.","JPN":"これは怪しいですね。入らないほうがいいと思います。","ENG":"Something’s not right. We shouldn’t go in there.","TWN":"情況不太對，我看還是別進去吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"소녀여, 범인에 대한 단서가 있으면 이 앞이 함정이라도……. ","JPN":"少女よ、犯人の手掛かりがあるのなら、例えこの先が罠であっても……","ENG":"Girl, if the clue is in there, then even if it’s a trap...","TWN":"少女，既然線索在裡面，那就算明擺著是陷阱，我們也……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"누군가 했더니 준이잖아? 네가 왜 여기 있는 거야?","JPN":"誰かと思ったらジュンじゃない？　なんで君がここにいるの？","ENG":"Is that you, Jun? What are you doing here?","TWN":"我還想說是誰咧，結果是朱恩？你在這裡幹嘛？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"으음? 아둔한 동생이야말로 왜 여기 온 거지?","JPN":"へえ？　冴えない我が妹こそ、ここに何の用だ？","ENG":"Huh? What brings you here, little sister?","TWN":"嗯？我才想問笨妹妹怎麼會在這裡？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"큭……. 그 때 지지만 않았어도 내가 누나 하는 건데…….","JPN":"くう……あの時負けてなければ、私がお姉ちゃんだったのに……","ENG":"Krr...! If I hadn’t lost that fight, I would be calling him little brother right now...!","TWN":"可惡……要不是我那時候打輸，現在我可是你姊姊好嗎……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"난 파사의 목소리가 여기로 가 달라고 해서 왔을 뿐이야.","JPN":"私は破邪の声に、ここに向かってほしいと言われて来ただけだよ。","ENG":"I’m here because the Voice of Evil Eradication told me to.","TWN":"是破邪之聲叫我來這裡的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그러는 너희야말로 여기서 뭔가 꾸미고 있는 건 아니겠지?","JPN":"あんたたちこそ、ここで何か企んでるわけじゃないよね？","ENG":"You guys aren’t scheming of doing something here, are you?","TWN":"倒是你們，不會是想在這裡作怪吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"만약 그렇다면 가만히 있지 않겠어!","JPN":"もしそうなら、ただじゃ済まないからね！","ENG":"If you are, then I will not allow it!","TWN":"要是被我逮到，我可不會放過你們！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"흥. 감찰과에서 정직 처분 받은 꼬맹이는 하나도 안 무섭네요.","JPN":"ふん、監察課から停職処分を受けたチビなんて全然怖くないもん。","ENG":"Hmph. Like we’d be scared of a punk who got suspended in Investigations.","TWN":"哼，被監察科停止處分的小鬼有什麼好怕的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"어떻게 할까요, 리더? 우선 한 발 물러서서 상황을 구경하는 걸 추천합니다만.","JPN":"どうしましょうか、リーダー？　まずは一歩下がって様子を見ることを\\nお勧めしますが。","ENG":"What should we do, Leader? I suggest we take a step back and watch how this plays out.","TWN":"老大，現在該怎麼辦？我個人是建議先觀察一下情況。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 지금으로서는 범인에 대한 단서가 더 중요해요.","JPN":"いいえ。今は犯人に関する手掛かりが最重要です。","ENG":"No. Right now, the clue is more important.","TWN":"不，現在更重要的是有關犯人的線索。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"별일 없을 거예요, 초원 씨. 다른 분들이 위험에 처해도 제가 대처해 드릴게요.","JPN":"心配しないでください、ナオさん。\\n他の方々が危険に晒されても、私が対処します。","ENG":"Everything will be fine, Chowon. If something happens, I’ll protect you and everyone else.","TWN":"不會有事的，萬一其他人發生危險，我也可以應付的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……알겠습니다. 고용주가 그렇게 말씀하시면 답이 없긴 하죠.","JPN":"……わかりました。クライアントにそう言われたら仕方ありませんね。","ENG":"...Okay. If that’s what you wish...","TWN":"……好吧，既然雇主這麼說，那我也沒什麼好說的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"어라? 아무것도 없는데?","JPN":"あれ？　何もないじゃない？","ENG":"Huh? There’s nothing here.","TWN":"嗯？沒人啊？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"겉으로 보기에는. 하지만 안경에 비치는 구조는…….","JPN":"見た目はそうでしょうね。でもメガネに映った構造は……","ENG":"Or it may seem. But from what I see through my glasses...","TWN":"那只是表象而已，我的眼鏡反射出來的結構……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"저기 벽을 밀어 봐. 숨겨진 공간이 있어.","JPN":"あの壁を押してみてください。隠し空間があります。","ENG":"Push that wall over there. There’s a hidden compartment inside.","TWN":"你推推看那道牆，後面有密室。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"정말?!","JPN":"本当に！？","ENG":"Really?","TWN":"真的嗎？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"흠, 지하실로 통하는 문이군.","JPN":"ふむ、地下室に繋がる扉だな。","ENG":"Hmm... Looks like a door to the basement.","TWN":"嗯，是通往地下室的門。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"이런 곳에 지하실……?","JPN":"こんなところに地下室……？","ENG":"A basement?","TWN":"這裡竟然有地下室……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그렇다면 이건……!","JPN":"つまり、ここは……！","ENG":"Then that means...!","TWN":"那這裡……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"악의 비밀기지가 틀림없어……!","JPN":"悪のアジトに違いないわ……！","ENG":"I’m positive that this is the secret evil lair...!","TWN":"肯定就是邪惡的秘密基地……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"우와, 진짜로 악의 비밀기지잖아?","JPN":"うわ、本当に悪のアジトかも。","ENG":"Whoa... It really is a secret lair...","TWN":"哇，秘密基地長得真的很邪惡欸！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"어……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"잠깐! 저기 있는 사람 실장님 아냐?","JPN":"ちょっと！　あそこにいる人、室長じゃない？","ENG":"Wait! Isn’t that Chief?","TWN":"等等！那個人不是室長嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니라고요?","JPN":"ホノカさんですって？","ENG":"You mean Jin?","TWN":"李珍姐？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그렇군. 어째서 구속 장치에 매달려 있는 거지?","JPN":"そうだな。しかしなぜ拘束装置に囚われているんだ？","ENG":"It is... But what’s she doing over there all tied up?","TWN":"真的是她，她怎麼會被綁在角落？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"늦었구나, 지아야.","JPN":"遅いじゃない、ユイちゃん。","ENG":"You’re late, Jia.","TWN":"小佳，你動作太慢了！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이 몸은 벌써 클론에 대한 단서를 확보했느니라.","JPN":"私はすでにクローンに関する手掛かりを確保できたわ。","ENG":"I already collected the clue about the clone.","TWN":"我已經找到有關複製人的線索！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"또 지아의 곁에서 지아를 기만하던 범인을 잡아냈지.","JPN":"そして、ユイちゃんの側でユイちゃんを騙していた犯人を捕まえたのよ。","ENG":"Also, I caught the suspect behind all of it.","TWN":"還揪出在你身邊欺騙你的犯人！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"범인……? 실장이 범인이라고?","JPN":"犯人……？　室長が犯人だと？","ENG":"The suspect...? You mean that Chief was the one behind it?","TWN":"犯人……？你說室長就是犯人？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……그렇다면 세실리아 씨가 마저 해결해 주세요. 이진 언니는 저와 더 이상 상관없는 사람이니까요.","JPN":"……それならセシリアさんが最後まで解決してください。\\nホノカさんはもう私とは関係ない人ですから。","ENG":"Then I want you to take care of it, Cecilia. She and I have nothing to do with each other anymore.","TWN":"……那就請你動手處理吧，李珍姐和我已經沒有關係了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"리더! 저 상황을 보고도 왜 자꾸 그래?!","JPN":"リーダー！　あの状況を見てそんなことが言えるの！？","ENG":"Leader! How can you say that after seeing all this?!","TWN":"老大！你怎麼現在還說這種話！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"후후, 경찰에게 넘기고 싶은 마음은 굴뚝 같다만, 네가 꼭 봐야 할 걸 찾아서 말이다.","JPN":"フフ、警察に身柄を渡したい気持ちは山々だけど、\\nぜひ君に見てほしい物を見つけてね。","ENG":"Fu fu. I wanted to turn her in, but I thought you might want to see this before I did.","TWN":"呵呵，雖然我也很想趕快把她交給警察，但你必須看一下這個。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"저 여자가 가지고 있던 보고서다. 그 때 우리가 본 클론에 대해 자세히 적혀 있더군.","JPN":"あの女が持っていた報告書よ。あの時、私たちが見たクローンについて\\n詳しく書かれていたの。","ENG":"This is the report she had with her. It has all the details about the clone we saw.","TWN":"這是在她身上找到的報告，裡面清楚記錄著複製人的資料！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"특이점 프로젝트……?","JPN":"特異点プロジェクト……？","ENG":"Singularity Project...?","TWN":"奇異點計畫……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"잠깐!","JPN":"待って！","ENG":"Wait!","TWN":"先等一下！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"보고서가 실장님이 범인이란 증거라고? 말도 안 돼!","JPN":"その報告書が室長が犯人だという証拠だって？　あり得ない！","ENG":"That report is proof that Chief is the culprit? Don’t kid yourself!","TWN":"光憑那個報告就說室長是犯人？會不會太誇張！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"당장 실장님 안 풀어 주면 언니한테 혼난다?!","JPN":"今すぐ室長を解放しないならお姉ちゃん、怒るよ！","ENG":"You let her go right now, or I’m gonna spank you!","TWN":"你還不快點把室長鬆開，姊姊要生氣囉！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"흥. 상황 파악도 안 될 만큼 머리가 나쁘면 빠져 있어라.","JPN":"ふん、状況把握もできないくらい頭が悪い子は黙ってなさい。","ENG":"Hmph. If you don’t see what’s going on, then I suggest you back off.","TWN":"哼，搞不清楚狀況的笨蛋，你哪邊涼快哪邊去吧！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"뭐야?!","JPN":"なんですって！？","ENG":"What?!","TWN":"你說什麼？！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아까부터 실장님 타령을 한다만…….","JPN":"さっきから室長、室長ってうるさいけど……","ENG":"You keep saying \\"Chief this\\" and \\"Chief that,\\" but...","TWN":"從剛剛就一直室長長、室長短的……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨에게 무언가 기묘한 재능이 있다는 건 인정하겠습니다만……. 그저 그뿐입니다.","JPN":"お嬢様に何か不思議な才能があることは認めますが……ただ、それだけです。","ENG":"I will admit that she has an uncanny ability... But that’s all there is to it.","TWN":"我承認小姐是有特殊的能力沒錯……但就僅此而已。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 외에는 부모 말 잘 듣는 아이일 뿐이죠. 공략할 수 있는 부분은 다른 또래들보다 더 많은 편입니다.","JPN":"それ以外は、親の言うことをよく聞く子どもでしかありません。\\nむしろ、付け込める要素は同年代の子どもたちよりも多いほうです。","ENG":"Other than that, she’s just a girl who listens to her parents. However, she does seem to be more vulnerable than her peers.","TWN":"除此之外，小姐不過就只是個聽話的孩子。 她比其他同年紀的孩子都還沒有心機。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"흐음……. 뭔가 잊은 것 같군, 이 실장.","JPN":"ふむ……何か忘れていないか、シノザキ室長。","ENG":"Hmm... I think you’re forgetting something, Chief Lee.","TWN":"嗯……李室長，你是不是忘了？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"나는 기회가 생겼을 때 그 괴물을 없애라고 자네를 이노베이션에 심어 둔 걸세.","JPN":"私はあの化け物を消す機会を窺うために、\\n君をイノベーションに潜入させたつもりだ。","ENG":"I put you in Innovation so that you can get rid of her when the opportunity arises.","TWN":"當初我派你去改革時，是要你一有機會就把那個怪物除掉。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내가 언제 자네에게 베이비시터 노릇까지 하라고 했던가?","JPN":"君に子守りの役まで頼んだおぼえは無いが？","ENG":"Did I put you on babysitting duties?","TWN":"我是叫你去當保母的嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이건 이 여자와 부회장이 나눈 대화의 녹취록이다.","JPN":"これはこの女と副会長が交わした会話の録音データよ。","ENG":"Here’s a transcript of the conversation she had with the Vice Chairman.","TWN":"這是那女的和副會長的對話錄音。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이 여자는 처음부터 여차하면 지아를 죽이려고 부회장이 심어 둔 끄나풀이야.","JPN":"この女は最初から、いざとなったらユイちゃんを殺せるよう副会長が潜入させたスパイなの。","ENG":"All this time, she was a mole placed by the Vice Chairman to kill Jia.","TWN":"這女的是副會長安排在小佳身邊的內賊，打算找機會要了小佳的命！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"영특한 지아는 그걸 알면서도 용서해 줬지.","JPN":"賢いユイちゃんはそれを知りながら許してやった。","ENG":"Clever Jia knew about it all this time, and forgave her.","TWN":"聰明如小佳，雖然很清楚她的目的，卻還是寬恕她。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"내 말이 틀리니, 지아야?","JPN":"そうでしょう、ユイちゃん？","ENG":"Am I wrong, Jia?","TWN":"我有說錯嗎，小佳？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"저 아줌마가 부회장이랑 같은 편이었다고?","JPN":"あのおばさんが副会長の手下だったと？","ENG":"So she was in it with the Vice Chairman?","TWN":"那個大嬸和副會長是同一國的喔？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그럼 왜 부회장이 살해당한 거야?","JPN":"じゃあ、なんで副会長は殺されたの？","ENG":"Then why was he assassinated?","TWN":"那副會長怎麼會被殺？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"당연히 내분이 있었겠지. 아마 이 보고서 탓에 말이다.","JPN":"内紛があったに違いないわ。おそらくこの報告書のせいでね。","ENG":"Why do you think? It's because of internal conflicts, or possibly because of this report.","TWN":"當然是因為內鬨吧？可能跟這份報告有關。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뻔뻔하게 지아 시중을 드는 척 하던 여자가 자기 주인이라고 물지 못할 법 있나?","JPN":"図々しくユイちゃんに仕えてるふりをしていた女だから、\\n自分の主に歯向かうのもあり得る話でしょ？","ENG":"Is there any reason she wouldn't bite her owner's hand? She's clearly not ashamed of pretending to serve Jia.","TWN":"她都可以裝作一副沒事的樣子待在小佳身邊，就算反咬自己的主人也不意外吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"결국 심문하면 다 불게 되어 있어.","JPN":"尋問すればすぐ自白するでしょうね。","ENG":"We’ll know everything after the interrogation.","TWN":"只要拷問她就會全盤托出吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"마침 블랙 네트워크에서 아주 특별한 자백제를 구해 왔으니…….","JPN":"ちょうどブラックネットワークで特別な自白剤を手に入れたから……","ENG":"I even found a special truth serum on the Dark Network to give her...","TWN":"剛好我這裡有從黑色網路找到的吐實劑……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저기…….","JPN":"あの……","ENG":"I’m sorry to interrupt...","TWN":"請問……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 연기, 계속 하실 건가요? <color=#ffd34c>고모님</color>?","JPN":"その演技、いつまで続けるつもりですか？　<color=#ffd34c>叔母様</color>？","ENG":"But how much longer are you going to keep this up, <color=#ffd34c>Auntie</color>?","TWN":"你打算繼續演下去嗎？<color=#ffd34c>姑姑</color>？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"응? 뭐라고?","JPN":"うん？　今なんて？","ENG":"Huh? What did you just say?","TWN":"嗯？你說什麼？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 헷갈리시면 이렇게 불러드릴까요?","JPN":"あ、わかりづらいならこのようにお呼びしましょうか？","ENG":"Oh, or would you prefer if I called you by your other name?","TWN":"不明白嗎？還是我換個稱呼？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스 <color=#ffd34c>바이오닉스</color> 대표님.","JPN":"アルファトリックス・<color=#ffd34c>バイオニクス</color>代表。","ENG":"CEO of Alphatrix <color=#ffd34c>Bionics</color>?","TWN":"阿爾法崔克斯<color=#ffd34c>仿生</color>代表。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"무…….","JPN":"な……","ENG":"Wh...","TWN":"你……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"무슨 소리냐, 지아야. 내 이름은 세실리아 신이라고 했을 텐데.","JPN":"何を言っているの、ユイちゃん。私の名前はセシリア・ヒメノよ？","ENG":"What nonsense, Jia. I thought I told you that my name is Cecilia Shin.","TWN":"你在說什麼，我的名字是賽希莉亞！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇군요. 여기 오면 솔직하게 말씀해 주시길 바랐는데…….","JPN":"そうですか。ここに来たら正直に話してくれると思っていたのに……","ENG":"I see. I was hoping you’d tell me the truth...","TWN":"是嗎？我本來還希望到這裡後，你會自己說實話……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"숨기려고 하셔도 소용없어요. 고모님은 벌써 세 번이나 실수를 하셨거든요.","JPN":"隠しても無駄です。叔母様はすでに3回も過ちを犯しましたから。","ENG":"But there’s no point in hiding it now. You’ve already made three mistakes.","TWN":"已經瞞不住了，姑姑，因為你犯了三次錯誤。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"세 번? 내가 세 번이나 악수를 뒀다고?","JPN":"3回？　私が3回も悪手を打ったと？","ENG":"Three? Are you saying I made three blunders?","TWN":"三次？你說我下錯棋三次？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 초원 씨, 안경을 잠깐 빌려 주시겠어요?","JPN":"はい。ナオさん、ちょっと眼鏡を貸していただけますか？","ENG":"Yes. Chowon? Could I borrow your glasses for a moment, please?","TWN":"對。初源，眼鏡可以借我一下嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……알겠습니다. 리더.","JPN":"……わかりました、リーダー。","ENG":"Here you go, Leader.","TWN":"……沒問題，老大。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이 알파 비전은 이노베이션의 활동을 촬영, 분석하기 위해 만들어진 데이터 수집기에요.","JPN":"このアルファビジョンはアルファトリックス・イノベーションの活動を撮影、分析するために作られた\\nデータ収集機です。","ENG":"Alpha Vision is a data collector made to record and analyze the activity at Innovation.","TWN":"這個阿爾法願景，會將改革的行動錄製下來，加以進行分析後收集資料。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다시 말해 별도의 조작 없이도 촬영과 녹음이 계속되고 있다는 말이죠.","JPN":"つまり、特別な操作をしなくても撮影と録音が続いているということです。","ENG":"In short, it is constantly recording audio and video.","TWN":"也就是說，不需要額外的操作，它也會持續錄影跟錄音。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러면……. 나와 대화를 나눌 때도 계속 찍고 있었다고?","JPN":"ってことは……私と会話する時もずっと撮っていたってこと？","ENG":"Then... It even has our conversations recorded on there?","TWN":"意思是……我和你的對話也有錄下來？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 그 때도 이노베이션으로 활동 중이었으니까요.","JPN":"はい、あの時もアルファトリックス・イノベーションとして活動中でしたので。","ENG":"Of course. I was on duty as Innovation at the time.","TWN":"沒錯，因為那也算是改革的行動。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"처음 저희가 만났을 때, 고모님은 범인에 대해 이런 말씀을 하셨어요.","JPN":"私たちが初めて会った時、叔母様は犯人についてこんなことをおっしゃいました。","ENG":"When we first met, you said this to me about the suspect.","TWN":"我們初次見面時，有關犯人的事，姑姑是這麼說的。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"으음……. 참 고약한 경우가 다 있구나.","JPN":"うーん、本当にひどい話だわ。","ENG":"Hmm... You must be going through a lot.","TWN":"嗯……聽起來確實滿慘的！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"범인이랑 얼굴이 비슷한 것 가지고 살인범으로 몰다니……. 죄다 경솔한 것들뿐이군.","JPN":"犯人と顔が似てるからって、それだけで殺人犯扱いだなんて……\\n浅はかな奴らばかりなのね。","ENG":"Calling you a murderer because you look similar to the culprit...? That’s the worst excuse I’ve ever heard.","TWN":"竟然因為長得和犯人很像，就被人當作是殺人犯……似乎太過草率！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래서? 이게 뭐 어쨌다는 거니?","JPN":"それで？　だからなんだって言うの？","ENG":"So? What’s that got to do with this?","TWN":"然後呢？有怎麼樣嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 시점에는 범인의 정체를 몰랐으니까, 저렇게 말해도 이상하지 않지.","JPN":"あの時点では犯人の正体がわからなかったから、この会話はおかしくないわ。","ENG":"We didn't know who the murderer was at the time, so it's not surprising.","TWN":"我那個時候又不知道犯人是誰，那麼說很正常吧？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 맞아요. 범인의 정체를 모르셨죠.","JPN":"はい、そうです。叔母様は犯人の正体を知らない状態でした。","ENG":"Yes, you’re right. We didn’t know who it was.","TWN":"是的，沒錯，那時候還不知道犯人是誰。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 헤비암즈 사무실에서 고모님은 이렇게 말씀하셨어요.","JPN":"ですが、ヘビーアームズのオフィスで叔母様はこうおっしゃいました。","ENG":"However, at the Heavyarms office, this is what you said.","TWN":"不過在重武裝辦公室時，姑姑這麼說的。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 혼란스럽겠지만 내 말 잘 듣거라.","JPN":"ユイちゃん、混乱しているでしょうけど、私の言うことをよく聞きなさい。","ENG":"Jia, I know you’re in shock, but listen to me carefully.","TWN":"小佳，你聽完可能會覺得有點混亂，但你仔細聽我說！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이사회에 클론의 존재를 밝혀 봤자 오히려 네 입장만 곤란해질 거다.","JPN":"理事会にクローンの存在を明かしても、むしろあなたの立場が悪くなるだけだわ。","ENG":"Telling the board about the clone is only going to make things worse for you.","TWN":"要是被董事會發現有複製人，你可能會更麻煩。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어떻게 헤비암즈에 막 도착하신 상황에서 실행범이 클론인 줄 알아차리셨을까요?","JPN":"ヘビーアームズに到着したばかりの状況で、どうして実行犯が\\nクローンだと気づいたのでしょう？","ENG":"How did you know that the killer was a clone as soon as you arrived at Heavyarms?","TWN":"那時才剛抵達重武裝而已，怎麼可能馬上就知道犯人是複製人？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 그 실행범이 클론이라고 들은 건 재혁 오라버니로부터였는데 말이에요.","JPN":"私にその実行犯がクローンだと教えてくれたのはタツヤお兄様だったのに。","ENG":"I only heard that it was a clone because Jaehyuk told me so.","TWN":"是大哥告訴我，我才知道原來行兇的人是複製人的。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님이 카운터라면 그와 관련된 능력을 가지고 계실지도 모르겠지만…….","JPN":"叔母様がカウンターなら、それを知ることができる能力を\\n持っていらっしゃるかもしれませんが……","ENG":"If you were a Counter, it would’ve made more sense, but...","TWN":"如果因為姑姑是制裁者，所以有類似能力，那還說得過去……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"본인은 저에게 줄곧 카운터가 아니라고 주장하셨잖아요?","JPN":"これまで何度も私にカウンターではないと主張していたでしょう？","ENG":"You’ve been stating that you’re not, haven’t you?","TWN":"但你不是一直堅持自己不是制裁者嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇다면 답은 하나. 고모님은 처음부터 실행범이 클론인 줄 알고 계셨던 거예요.","JPN":"それなら答えは一つです。\\n叔母様は最初から実行犯がクローンだと知っていたんです。","ENG":"Then there’s only one conclusion. You knew who the killer was from the start, Auntie.","TWN":"那麼答案就只有一個，也就是姑姑你從頭到尾都知道行兇的是複製人。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"잠깐, 그럼…….","JPN":"ちょっと待って、つまり……","ENG":"Hold on. Then...","TWN":"等等，所以說……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"맞아. 저 꼬마가 이번 사건에서 최소 공범 이상이라는 뜻이야.","JPN":"そうです。あのチビが今回の事件において、少なくとも共犯以上という意味になります。","ENG":"Yeah. That kid’s got something to do with everything that happened.","TWN":"沒錯，那個小鬼一定有參與這次的事件。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"흐음, 듣고 나니 확실히 이상하지만…….","JPN":"ふうん。そう言われたら確かに怪しいと思われても仕方ないけど……","ENG":"Hmm... Now that you mention it, it does sound weird...","TWN":"嗯嗯，聽你分析完，確實是有可疑之處……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"말실수 하나로 트집 잡는 건 너무하지 않니?","JPN":"たった失言一つで言いがかりをつけるのはひどいんじゃない？","ENG":"But don’t you think it’s a stretch accusing me over a tiny mistake?","TWN":"但我不過就是說錯一句話，有需要這樣找我麻煩嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 그렇지만 고모님의 두 번째 실수는 밸런스 브레이커를 너무 많이 생산하신 거예요.","JPN":"それだけではありません。叔母様の2つ目のミスは、バランスブレイカーを生産しすぎたことです。","ENG":"True. But your second mistake was producing too many Balance Breakers.","TWN":"當然不只如此，姑姑犯的第二個錯，就是大量生產平衡破壞者。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"많이 생산했다……?","JPN":"生産しすぎた……？","ENG":"Too many...?","TWN":"大量生產……？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"밸런스 브레이커는 가격 때문에 많이 생산하기 어려운 무기니까요.","JPN":"バランスブレイカーはその価格のせいで、大量生産には向いていない武器です。","ENG":"Balance Breaker is a difficult weapon to produce due to its high cost.","TWN":"平衡破壞者的製造成本高昂，因此無法大量生產。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런 고가의 무기를 여러 정 생산할 정도라면, 그걸 쓸 클론들도 그만큼 있다는 뜻이겠죠?","JPN":"そんな高価な武器を複数生産するということは、\\nそれを使うクローンもそれだけいるということでしょう。","ENG":"But if you were to have produced that many of them, it can only mean that you have created as many clones.","TWN":"既然製造出那麼多高價的武器，那當然也就要有足夠數量的複製人吧？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스 그룹에서도 그런 설비를 갖춘 곳은 한 곳뿐이에요.","JPN":"アルファトリックスグループの中でも、そんな設備を揃えているところは\\n一か所しかありません。","ENG":"And there’s only one place in Alphatrix capable of making that many.","TWN":"而在阿爾法崔克斯集團中，只有一個地方有這種設備。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"바로 고모님의 <color=#ffd34c>알파트릭스 바이오닉스</color>죠.","JPN":"叔母様の<color=#ffd34c>アルファトリックス・バイオニクス</color>です。","ENG":"That would be your <color=#ffd34c>Alphatrix Bionics</color>.","TWN":"就是姑姑的<color=#ffd34c>阿爾法崔克斯仿生</color>。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……고작 그런 이유로?","JPN":"……その程度の話で？","ENG":"Is that your reasoning?","TWN":"……只因為這樣？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어차피 정황 증거에 불과한데? 바이오닉스 대표부터 찾는 게 상식 아닐까?","JPN":"そんなの状況証拠にすぎないわよ？\\nまずは私じゃなくて、バイオニクスの代表を探すのが常識じゃない？","ENG":"Doesn’t seem like substantial evidence to me? Wouldn’t finding out who the CEO of Bionics be the priority?","TWN":"聽起來只是間接證據而已？先找上仿生代表是正常的吧？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다행히 그 부분에 대해선 저보다 먼저 짚어 주신 분이 계시거든요.","JPN":"幸い、それについて私より先に気づいた方がいました。","ENG":"Luckily, someone else had already done that for us.","TWN":"幸好有人比我早發現這一點。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"경위님께서 세실리아란 분을 조사해 주셨어요.","JPN":"マエカワ警部補がセシリアという人物について調べてくれました。","ENG":"You see, Lieutenant Kang did a background check on the name Cecilia.","TWN":"警衛已經調查過賽希莉亞這個人，"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어머니 집안의 특허권을 빼앗긴 뒤 버려진 채 난민지구를 전전하다가…….","JPN":"母方の家の特許権を奪われた後、\\n捨てられた身で難民地区を転々としていましたが……","ENG":"She was abandoned and wandered around the refugee district after her mother's family lost their patent rights...","TWN":"媽媽的專利被奪走後，她就流落到難民區……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"얼마 전 소식이 두절되었다고 해요.","JPN":"しばらく前に消息が途絶えたそうです。","ENG":"Then disappeared recently.","TWN":"不久前彷彿人間蒸發，都沒有她的消息。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 여자가……?","JPN":"あの女が……？","ENG":"She what...?","TWN":"那女人調查我……？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"역시 경찰 분들은 대단하세요.","JPN":"さすが警察の方はすごいですね。","ENG":"The police here are outstanding.","TWN":"警察很厲害吧！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠깐 마주쳤을 뿐인데 이상한 점을 바로 알아차리셨잖아요? 그렇죠?","JPN":"ほんの少し会っただけなのに、怪しい点にすぐ気づいたんですよ？","ENG":"It was only a brief encounter, but they noticed something odd right away.","TWN":"是不是？只是稍微見過面而已，就可以立刻察覺到不對勁的地方。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그건……. 그 경찰이 별종 같군.","JPN":"それは……その警察が特別なだけだと思うが。","ENG":"That’s because... that cop is a weirdo.","TWN":"呃……那位警察好像是特例。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그러면 뭐야? 저기 있는 쟤는?","JPN":"じゃあ誰なの？　そこにいる子は？","ENG":"Hold on. Then who’s she?","TWN":"所以呢？她到底是誰？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"불법 유통된 아티팩트……. 내지는 실제로 외과적인 성형 수술을 동원했을 수도 있어.","JPN":"違法に入手したアーティファクト……\\nあるいは、実際に整形手術を行ったかもしれない。","ENG":"An illegally smuggled Artifact... Or she could’ve gotten surgery to change her appearance.","TWN":"可能是非法流通的人造物……甚至可能真的有動整型手術。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"제식 장비의 생체신호를 속일 정도의 생명공학 기술이라면 불가능한 일도 아니야.","JPN":"制式装備の生体信号を欺けるほどの生命工学技術なら、\\n不可能なことでもないでしょう。","ENG":"If she has the technology to spoof the biometric signals, it’s not entirely impossible.","TWN":"要騙過制式裝備的身分信號，只要利用生物技術應該不是難事。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이런…….","JPN":"あら……","ENG":"Oh my...","TWN":"竟然……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이 정도까지 몰리니 세 번째도 궁금해지는걸.","JPN":"ここまで追い詰められたら、3つ目も気になるわね。","ENG":"Since you’ve got me all cornered, I wonder what the third blunder is.","TWN":"可以把我逼到這種程度，讓我更好奇第三個是什麼呢！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"마지막은 뭐니, 지아야?","JPN":"最後は何かしら、ユイちゃん。","ENG":"So, what’s my last blunder, Jia?","TWN":"你說吧，小佳！最後一個是什麼？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아. 세 번째는 곧 저지르실 거예요.","JPN":"あ、3つ目はこれからすると思います。","ENG":"Your third mistake is going to happen soon.","TWN":"喔，第三個錯誤你正要犯。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐……?","JPN":"なんですって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"왜냐하면…… <color=#ffd34c>고모님은 기물을 소중하게 안 다루시니까요.</color>","JPN":"なぜなら……<color=#ffd34c>叔母様は一駒一駒を大切に扱わないからです。</color>","ENG":"Because... <color=#ffd34c>you don’t treat your pieces with respect, Auntie.</color>","TWN":"因為……<color=#ffd34c>姑姑在下棋時沒有步步為營</color>。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 기풍이 분명 고모님의 발목을 잡을 거예요.","JPN":"その棋風がきっと叔母様の足を引っ張るでしょう。","ENG":"That kind of attitude will surely come to bite you back.","TWN":"姑姑的棋路會絆倒你自己的。"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Krr...","TWN":"唔……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하, 아하하하하하하하핫!!","JPN":"ハハ、アハハハハハハッ！！","ENG":"Hah! Ahahahahaha!!","TWN":"哈，哈哈哈哈哈哈！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"십 몇 년도 더 된 대국을 아직도 기억해 주다니 이거 영광이구나, 지아야.","JPN":"十数年前の対局を未だに覚えてくれてるなんて嬉しいわ、ユイちゃん。","ENG":"I’m surprised you still remember our little game back from all those years, Jia!","TWN":"這盤棋下了十幾年，你竟然還記得，我真是榮幸呢，小佳。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"나름대로 블러핑에 공을 기울였는데 네게는 소용없었던 모양이네.","JPN":"それなりにブラフィングに力を入れたつもりだけど、あんたには無駄だったようね。","ENG":"I’ve put in a lot of effort into my bluffing, but it seems that it’s no use against you.","TWN":"虧我還演得這麼認真，看來還是沒能騙過你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"얼굴과 신분까지 속여 가면서……. 대체 왜 이런 짓을 저지르신 거죠?","JPN":"顔と身元まで偽って……いったいなぜこんなことをしたのですか？","ENG":"Why are you doing this while going to the extent of concealing your identity and even your face?","TWN":"你用別人的臉和身分來欺騙我們……你到底為什麼要這麼做？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……왜냐고?","JPN":"……なぜかって？","ENG":"Why, you ask?","TWN":"……你問我為什麼？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님의 목표는 저 하나 아닌가요?","JPN":"叔母様のターゲットは私一人じゃないですか？","ENG":"Isn’t it me who you want?","TWN":"姑姑的目標不是我嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"많은 분들이 이번 일로 피해를 입었어요. 숙부님처럼 목숨을 잃은 분들도 계시고요.","JPN":"たくさんの方々が今回の件で被害を受けました。\\n叔父様のように亡くなられた方もいらっしゃいます。","ENG":"But instead, you caused pain and suffering to others. Some have even lost their lives like my uncle.","TWN":"可是卻有這麼多人因為這次的事件受傷，叔叔甚至還因此喪命！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런데, 대체 왜…….","JPN":"なのに、いったいどうして……","ENG":"Why would you...?","TWN":"你到底為什麼……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너, 정말……","JPN":"あんたはさ、まったく……","ENG":"Are you really...","TWN":"你……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"정말 몰라서 묻니, 그걸?","JPN":"本当にわからなくて聞いてるの？","ENG":"Asking because you don’t know?","TWN":"是真的不知道才問的嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"내 정체는 잘만 알아차리면서 정작 이유는 모르겠다고? 관심이 없는 거겠지!!","JPN":"私の正体は突き止めたくせに、肝心の理由がわからないって？\\n興味ないだけでしょ！！","ENG":"You figured out it was me, but not my motives? More like you didn’t even bother!!","TWN":"你已經知道我的身分，卻還不知道我真正的理由？你是不知道還是不想知道！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뻔하잖아! 네가 먼저 내 모든 걸 빼앗아 갔으니까!","JPN":"決まってるじゃない！　あんたが先に私のすべてを奪っていったからよ！","ENG":"Isn’t it obvious? You took everything away from me!","TWN":"這不是很明顯嗎！因為你奪走我的一切！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아, 그거야. 바로 그 표정…….","JPN":"ああ、それよ。まさしくその顔……","ENG":"Yeah, that’s it. It’s that exact look...","TWN":"沒錯！就是這個表情……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"순진한 척, 아무것도 모르는 척 하는 그 역겨운 표정……!","JPN":"純粋なふり、何も知らないふりをするその反吐が出そうな顔……！","ENG":"That disgusting look of acting all innocent and pure...!","TWN":"一臉無辜，好像什麼都不知情的噁心嘴臉……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너 정말 모르는 거니? 네 존재 자체가 우리 같은 평범한 사람들에게 얼마나 개 같은지?","JPN":"あんた本当に知らないの？　あんたの存在自体が、私たちのような\\n平凡な人間にとって、どれほどクソみたいなものなのか！","ENG":"Are you that clueless? Do you know how infuriating your existence is to people like me?","TWN":"你是真的不知道嗎？你的存在，對我們這種普通人而言有多討厭！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"내가 받았어야 할 아빠의 사랑도! 그럴 때 항상 감싸 주던 큰 오빠도!","JPN":"私が受けるべきだった父さんの愛も！　いつも味方になってくれた兄さんも！","ENG":"The love I should’ve received from my father and brother!","TWN":"不只是爸爸的愛！還有那時候常常維護我的大哥！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그리고…… 내가 살면서 유일하게 자부심을 느꼈던 체스까지 네가 다 빼앗아 갔어!!","JPN":"そして……私の人生で唯一自負していたチェスまで、\\nあんたが全部奪っていったわ！！","ENG":"And even chess... the one thing I was proud of...! You took everything away from me!!","TWN":"就連……我人生中唯一感到驕傲的西洋棋，你也要搶走！！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 날 단 한 번의 대국으로!!","JPN":"あの日、たった一回の対局で！！","ENG":"All with just one game that day!!","TWN":"就在那天那場對弈中！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"알아?! 그 날 나타난 워치도 나에겐 패배자의 낙인에 불과해!","JPN":"わかってるの！？　あの日現れたウォッチも、私には負け犬の烙印に\\nすぎないのよ！","ENG":"You know what?! The Watch that appeared that day was nothing but a mark of failure!","TWN":"你知道嗎？！那天出現的能量環也是在告訴我，我是個失敗者！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L34_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"네 모가지를 졸라 비틀어 버리고 싶은 마음을 간신히 참고 있을 때!! 이 빌어먹을 게 나타났다고!!","JPN":"あんたを絞め殺したい気持ちを辛うじて我慢していた時！！\\nこのクソみたいな時計が現れたの！！","ENG":"Just when I was almost about to twist that neck of yours!! This damn thing stopped me!!","TWN":"我費多大的力，才忍住想要扭斷你脖子的衝動！該死的傢伙！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……그런데 뭐? 많은 분들이 피해를 입어?","JPN":"……なのに、なに？　たくさんの方々が被害を受けた？","ENG":"And yet... You say that I made people suffer?","TWN":"……你還說什麼？有許多人因此受傷？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"나도 피해자야! 네가 난도질해 놓고! 갈기갈기 찢어 놓고는!","JPN":"私も被害者よ！　私の胸をえぐって！　身を裂くような思いをさせられて！","ENG":"I’m also the victim here! You ripped my life to pieces!!","TWN":"我也是受害者好嗎！因為你的關係，害我失去多少東西！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아무것도 모르는 척 불운한 공주님 행세를 하던 네가! 그딴 소리가 나와?!","JPN":"何も知らないふりをして不幸なお姫様を演じていたあんたに！\\nあんたにそんなことを言う資格はない！","ENG":"So how dare you say that to me while you pretend to be the clueless damsel in distress!!","TWN":"而你竟然還裝得一副無辜樣，好像落難公主一樣！你憑什麼說那些話？！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너에게서 내 걸 되찾으려면……. 상식적인 방법으로는 안 돼.","JPN":"あんたから私のものを取り戻すには……常識的な方法じゃダメだったわ。","ENG":"If I want to take back what’s mine from you... Conventional methods are useless.","TWN":"我要從你身上奪回原本屬於我的東西……就不能用一般的方法。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"세상 전부를 베팅할 각오가 없으면 안 된다고!!","JPN":"世界全部を賭ける覚悟がないとダメだったの！！","ENG":"I need to put everything on the line just to have my shot!!","TWN":"沒有賭上全世界的決心是不行的！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……고모님.","JPN":"……叔母様。","ENG":"Auntie...","TWN":"……姑姑。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님 말씀대로……. 저는 고모님이 얼마나 아파했는지 이해할 수 없을지도 몰라요.","JPN":"叔母様のおっしゃるとおり……私は叔母様がどれほど辛かったのか、\\n理解できないかもしれません。","ENG":"As you said, I may not understand the pain you've gone through.","TWN":"姑姑說的沒錯……或許我確實無法理解姑姑的痛苦，"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 한 가지는 알아요.","JPN":"ですが、一つだけわかることがあります。","ENG":"But I know this.","TWN":"但我很清楚一件事，"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님이 지금껏 저지르신 행동은…… 평범하지도, 올바르지도 않아요.","JPN":"叔母様が今まで犯した行動は……普通でも正しくもありません。","ENG":"The actions you’ve committed... they cannot be justified no matter what.","TWN":"就是姑姑至今的所作所為……不是一般人該有的行為，完全不正當！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하……! 하하!","JPN":"ハ……！　ハハッ！！","ENG":"Ha! Haha!","TWN":"哈……！哈哈！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래. 하긴, 사람 손에서 만들어진 주제에 사람 마음을 어떻게 알겠어.","JPN":"そうね。確かに、人間の手で作られたものに人間の心なんか\\nわかるはずがないわ。","ENG":"You’re right. How can an experiment like you understand what it’s like to be human.","TWN":"也是，藉由人手所造出來的東西，怎麼會理解人類的心情呢？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"오라버니는 너 같은 괴물은 이 세상에서 없어져야 한다고 믿었어.","JPN":"副会長だった兄さんは、あんたみたいな化け物がこの世から消えるべきだと信じていたわ。","ENG":"My brother believes that monsters like you shouldn’t exist in this world.","TWN":"大哥一直認為，像你這種怪物，根本就不該存在於這個世界上。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그런데 내 생각은 좀 달라.","JPN":"でも私の考えは違う。","ENG":"But I have a different opinion.","TWN":"但我的想法和大哥不一樣。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"판돈을 잃었으면, 잃은 만큼 따고 자리에서 일어나야지.","JPN":"賭け金を失ったなら、失った分を取り戻してから席を立たないと。","ENG":"If you lose a bet, you double down and recover your loses before leaving the table.","TWN":"我認為，從哪裡賭輸，就要從哪裡贏回來！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"겨우 내 정체를 밝힌 걸로 체크메이트를 외치려고 했다면 오산이야.","JPN":"私の正体を明かした程度でチェックメイトをしたつもりなら大間違いよ。","ENG":"If you think it’s checkmate just because you’ve exposed me, you’re making a big mistake.","TWN":"你以為知道我的身分，就可以喊將軍嗎？沒這麼容易的事！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이번엔 나도 만반의 준비를 갖췄으니까.","JPN":"今回は私も万全の準備を整えたからね。","ENG":"Because I came prepared as well.","TWN":"我這次可是有做好萬全的準備！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 날 대국은 쓸데없이 너무 공정했다고 생각하거든……!","JPN":"あの日の対局は無駄に公正すぎたと思ったのよ……！","ENG":"I always thought the game we played was overly fair...!","TWN":"那天的對弈都怪我手腳太乾淨……！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"저 애 뭐야? 갑자기 남자 목소리로 바뀌었어!","JPN":"あの子なんなの？　急に男の声に変わった！","ENG":"What the heck? Her voice changed into a man’s!","TWN":"她是怎樣？怎麼突然變成男聲？！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"잠깐, 저 목소리는…….","JPN":"待って、あの声は……","ENG":"Wait… That voice…","TWN":"等等，那個聲音是……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>파사의 목소리</color> 님?!","JPN":"<color=#ffd34c>破邪の声</color>様！？","ENG":"Mr. <color=#ffd34c>Voice of Evil Eradication</color>?!","TWN":"<color=#ffd34c>破邪之聲</color>？！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"네가 추종하던 그 수상한 목소리라고? 그렇다면 처음부터 손바닥 위였다는 건가!","JPN":"君が従っていたあの怪しい声だと？\\nつまり最初から掌の上だったということか！","ENG":"That’s the weird voice you were following? Then that means she’s been playing you all this time!","TWN":"就是你說的那個詭異的聲音？所以從一開始就是算計好的嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"흥. 수상쩍은 설정에 혹하는 팔랑귀라 꽤 잘 써먹었지.","JPN":"ふん。怪しい設定に従うような性格で、上手いこと使えたわ。","ENG":"Hmpf. I had my fun swaying that gullible kid around with what she wanted to hear.","TWN":"哼，誰叫她耳根子軟，才會被人利用！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하지만 여기까지야. 괜히 더 들쑤시고 다니면 귀찮아지거든.","JPN":"でもここまでよ。これ以上勝手にかき回されたら面倒だから。","ENG":"But fun’s over now. It’ll only get bothersome if she starts poking around in places where she shouldn’t be.","TWN":"不過就到此為止，再繼續糾纏下去只會更麻煩。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뒤늦게 내 흉내를 내려던 오빠처럼 말이야.","JPN":"後から私の真似をしようとした兄さんのようにね。","ENG":"Just like how my brother tried to act like me.","TWN":"就跟我那個學人精哥哥一樣！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님, 그 목소리는……. 할아버님 것이잖아요?","JPN":"叔母様、その声は……お祖父様のものでは？","ENG":"That voice... Isn’t that Grandfather’s voice?","TWN":"姑姑，你那不是……爺爺的聲音嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"바로 맞췄구나. 역시 지아다워.","JPN":"そうよ。さすがだわ、ユイちゃん。","ENG":"Nothing gets past you, Jia.","TWN":"猜沒錯，真不愧是小佳！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러면 정식으로 다시 소개해야겠구나.","JPN":"それでは改めて紹介しよう。","ENG":"Now, allow me to introduce myself again.","TWN":"那我就正式跟大家介紹一下，"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래, 네 말대로 나는 방탕하단 이유만으로 집안에서 내쫓겼던 네 고모이자…….","JPN":"そう。あんたの言うとおり、私は道楽娘だという理由だけで\\n家から追い出されたあんたの叔母であり……","ENG":"Yes, I am your aunt. The black sheep of the family who got exiled for leading a life of debauchery...","TWN":"沒錯，如你所說，我就是那個因為不學好，而被趕出家門的姑姑……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너의 할애비란다.","JPN":"お前の祖父だ。","ENG":"And also your grandfather.","TWN":"同時也是你爺爺。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};